// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC1155/IERC1155.sol";

/**
 * @notice SplitsWarehouse interface for batch deposits
 * @dev Central ERC6909 token vault where all Splits ecosystem funds accumulate
 */
interface ISplitsWarehouse {
    function batchDeposit(
        address[] calldata receivers,
        address token,
        uint256[] calldata amounts
    ) external payable;
}

interface IReverseRegistrar {
    function setName(string memory name) external returns (bytes32);
}

/**
 * @title Strategy
 * @notice A strategy contract that distributes tokens to recipients based on weighted allocations
 * @dev Designed to be deployed via minimal proxy (clone) pattern
 *
 * PROOF OF CONCEPT - NOT PRODUCTION READY
 *
 * How it works:
 * 1. Curator creates strategy with weighted allocations
 * 2. Donors send tokens directly to strategy address (or via ENS)
 * 3. Anyone calls distribute() to route funds to recipients via warehouse
 * 4. Recipients withdraw from warehouse at their convenience
 *
 * Funding:
 * - ETH: Send directly, emits Funded event
 * - ERC20: Send directly, indexer watches Transfer events to strategy
 *
 * Security model:
 * - Non-custodial: Funds flow through warehouse, strategy never holds after distribution
 * - Transparent: All allocations and distributions on-chain
 * - Permissionless: Anyone can trigger distribution
 *
 * Known limitations (POC):
 * - No front-running protection on rebalance (production should add 24h timelock)
 * - No minimum distribution amount (production should add to prevent dust spam)
 * - Fee-on-transfer tokens NOT supported
 * - Rebasing tokens NOT supported
 * - No emergency pause mechanism
 */
contract Strategy is OwnableUpgradeable, ReentrancyGuardUpgradeable {
    using SafeERC20 for IERC20;

    /// @notice Maximum number of allocations allowed
    uint256 public constant MAX_ALLOCATIONS = 50;

    /// @notice Native ETH address per ERC-7528
    address public constant NATIVE_TOKEN =
        0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE;

    /// @notice SplitsWarehouse for batch deposits
    ISplitsWarehouse public immutable warehouse;

    /// @notice ENS ReverseRegistrar for reverse resolution (address -> name)
    IReverseRegistrar public immutable reverseRegistrar;

    struct Allocation {
        address recipient; // Recipient address (EOA, multisig, contract, or another Strategy)
        uint96 weight; // Relative weight (not percentage - calculated from totalWeight)
        string label; // Human-readable label (e.g. "Protocol Guild", "Curator Fee")
    }

    struct Config {
        address owner; // Strategy owner (can rebalance allocations)
        address sourceStrategy; // Parent strategy if forked, address(0) otherwise
        Allocation[] allocations; // Initial allocation configuration
        string metadataURI; // URI to off-chain metadata (title, description, image)
    }

    /// @notice Current allocations for distribution
    Allocation[] public allocations;

    /// @notice Total weight of all allocations (for percentage calculation)
    uint256 public totalWeight;

    /// @notice The strategy this was forked from (address(0) if original)
    address public sourceStrategy;

    /// @notice URI pointing to metadata JSON (title, description, image)
    string public metadataURI;

    /// @notice The factory that created this strategy
    address public factory;

    // Events
    event Funded(address indexed token, address indexed from, uint256 amount);
    event Rebalanced(Allocation[] allocations, string metadataURI);
    event Distributed(
        address indexed token,
        uint256 totalAmount,
        Allocation[] allocations
    );
    event Payout(
        address indexed recipient,
        address indexed token,
        uint256 amount
    );

    // Errors
    error ZeroWarehouseAddress();
    error NoAllocationsSet();
    error NoBalanceToDistribute();
    error TooManyAllocations();
    error ZeroAddressRecipient();
    error ZeroWeight();
    error WeightOverflow();

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor(address _warehouse, address _reverseRegistrar) {
        if (_warehouse == address(0)) revert ZeroWarehouseAddress();
        warehouse = ISplitsWarehouse(_warehouse);
        reverseRegistrar = IReverseRegistrar(_reverseRegistrar);
        _disableInitializers();
    }

    /**
     * @notice Receive function to accept native ETH
     * @dev Emits Funded event for indexer tracking
     * For ERC20 tokens, send directly - indexer watches Transfer events
     */
    receive() external payable {
        emit Funded(NATIVE_TOKEN, msg.sender, msg.value);
    }

    /**
     * @notice Fallback reverts to prevent accidental calls with data
     * @dev Use receive() for ETH funding, direct transfer for ERC20
     */
    fallback() external payable {
        revert("Use receive() for ETH deposits");
    }

    /**
     * @notice Initialize the strategy (called by factory)
     * @param config Strategy configuration
     * @param ensName Optional ENS name for reverse resolution (pass "" to skip)
     * @dev When ensName is provided, strategy calls reverseRegistrar.setName()
     *      which sets reverse record (strategy address -> name).
     *      This works because msg.sender = address(this) satisfies
     *      ReverseRegistrar's authorised(addr) check (addr == msg.sender).
     */
    function initialize(
        Config calldata config,
        string calldata ensName
    ) external initializer {
        __Ownable_init(config.owner);
        __ReentrancyGuard_init();
        factory = msg.sender; // Store the factory address
        sourceStrategy = config.sourceStrategy;
        metadataURI = config.metadataURI;
        _setAllocations(config.allocations);

        if (bytes(ensName).length > 0) {
            reverseRegistrar.setName(ensName);
        }
    }

    /**
     * @notice Update the allocation configuration and metadata
     * @param _allocations New allocation configuration
     * @param _metadataURI New metadata URI pointing to off-chain JSON
     * @dev Owner only. Changes take effect immediately on next distribution.
     *
     * PRODUCTION NOTE: Should implement timelock (e.g., 24h delay) to prevent
     * front-running attacks where owner sees large donation in mempool and
     * rebalances to capture funds before distribution.
     */
    function rebalance(
        Allocation[] calldata _allocations,
        string calldata _metadataURI
    ) external onlyOwner {
        _setAllocations(_allocations);
        metadataURI = _metadataURI;
        emit Rebalanced(_allocations, _metadataURI);
    }

    /**
     * @notice Set or update the ENS name for reverse resolution
     * @param ensName ENS name for reverse resolution (e.g., "mystrategy.support-dev.eth")
     * @dev Owner or factory only. Sets reverse record (strategy address -> name).
     */
    function setName(string calldata ensName) external {
        require(
            msg.sender == owner() || msg.sender == factory,
            "Only owner or factory"
        );
        reverseRegistrar.setName(ensName);
    }

    /**
     * @notice Transfer a wrapped ENS name (or any ERC1155 token) to a recipient
     * @param token Address of the ERC1155 contract (e.g., NameWrapper)
     * @param recipient Address to receive the token
     * @param tokenId Token ID to transfer
     * @param amount Amount to transfer (typically 1 for ENS names)
     * @dev Owner only. Use this to disconnect an ENS name from the strategy.
     */
    function transferERC1155(
        address token,
        address recipient,
        uint256 tokenId,
        uint256 amount
    ) external onlyOwner {
        require(recipient != address(0), "Zero address recipient");
        IERC1155(token).safeTransferFrom(
            address(this),
            recipient,
            tokenId,
            amount,
            ""
        );
    }

    /**
     * @notice Distribute the contract's balance of a token to recipients via SplitsWarehouse
     * @param token Address of the token to distribute (use NATIVE_TOKEN for ETH)
     * @dev Anyone can call this function. Distribution is permissionless.
     *
     * Process:
     * 1. Calculate each recipient's share based on weight
     * 2. Send all funds to warehouse in single batch
     * 3. Emit events for indexer tracking
     *
     * Rounding: Last recipient gets remainder to prevent dust accumulation
     *
     * PRODUCTION NOTE: Should implement minimum distribution amount to prevent
     * gas griefing attacks (e.g., MIN_DISTRIBUTION = 0.001 ETH)
     */
    function distribute(address token) external nonReentrant {
        if (totalWeight == 0) revert NoAllocationsSet();

        // Get balance (ETH or ERC20)
        uint256 balance = token == NATIVE_TOKEN
            ? address(this).balance
            : IERC20(token).balanceOf(address(this));

        if (balance == 0) revert NoBalanceToDistribute();

        // Calculate distributions for all allocations
        uint256 allocationsLength = allocations.length;
        address[] memory recipients = new address[](allocationsLength);
        uint256[] memory amounts = new uint256[](allocationsLength);
        uint256 distributed = 0;

        for (uint256 i = 0; i < allocationsLength; i++) {
            recipients[i] = allocations[i].recipient;

            if (i == allocationsLength - 1) {
                // Last recipient gets remainder to handle rounding dust
                amounts[i] = balance - distributed;
            } else {
                amounts[i] = (balance * allocations[i].weight) / totalWeight;
                distributed += amounts[i];
            }
        }

        // Batch deposit to SplitsWarehouse
        if (token == NATIVE_TOKEN) {
            // Native ETH deposit
            warehouse.batchDeposit{value: balance}(recipients, token, amounts);
        } else {
            // ERC20 deposit
            IERC20(token).forceApprove(address(warehouse), balance);
            warehouse.batchDeposit(recipients, token, amounts);
        }

        // Emit events after successful deposit
        emit Distributed(token, balance, allocations);
        for (uint256 i = 0; i < allocationsLength; i++) {
            if (amounts[i] > 0) {
                emit Payout(recipients[i], token, amounts[i]);
            }
        }
    }

    /**
     * @notice Get the contract's balance of a token
     * @param token Address of the token (use NATIVE_TOKEN for ETH)
     * @return The balance of the token held by this contract
     */
    function balanceOf(address token) external view returns (uint256) {
        if (token == NATIVE_TOKEN) {
            return address(this).balance;
        }
        return IERC20(token).balanceOf(address(this));
    }

    /**
     * @notice Get the number of allocations
     * @return The number of allocations
     */
    function getAllocationsCount() external view returns (uint256) {
        return allocations.length;
    }

    /**
     * @notice Get all allocations
     * @return Array of all allocations
     */
    function getAllocations() external view returns (Allocation[] memory) {
        return allocations;
    }

    /**
     * @dev Internal function to set allocations with validation
     *
     * Validates:
     * - Not too many allocations (max 50)
     * - No zero addresses
     * - No zero weights
     * - No weight overflow
     *
     * Does NOT validate:
     * - Duplicate recipients (allowed - not a security issue)
     * - Self-allocation (allowed - funds go to warehouse anyway)
     */
    function _setAllocations(Allocation[] calldata _allocations) internal {
        if (_allocations.length > MAX_ALLOCATIONS) revert TooManyAllocations();

        delete allocations;

        uint256 _totalWeight = 0;
        for (uint256 i = 0; i < _allocations.length; i++) {
            address recipient = _allocations[i].recipient;
            uint96 weight = _allocations[i].weight;

            // Validate recipient
            if (recipient == address(0)) revert ZeroAddressRecipient();

            // Validate weight
            if (weight == 0) revert ZeroWeight();

            // Check for weight overflow
            uint256 newTotal = _totalWeight + weight;
            if (newTotal < _totalWeight) revert WeightOverflow();
            _totalWeight = newTotal;

            allocations.push(_allocations[i]);
        }

        totalWeight = _totalWeight;
    }

    /// @notice ERC1155 receiver (required to hold wrapped ENS names temporarily)
    function onERC1155Received(
        address,
        address,
        uint256,
        uint256,
        bytes calldata
    ) external pure returns (bytes4) {
        return this.onERC1155Received.selector;
    }

    /// @notice ERC1155 batch receiver
    function onERC1155BatchReceived(
        address,
        address,
        uint256[] calldata,
        uint256[] calldata,
        bytes calldata
    ) external pure returns (bytes4) {
        return this.onERC1155BatchReceived.selector;
    }

    /// @notice ERC165 support
    function supportsInterface(
        bytes4 interfaceId
    ) external pure returns (bool) {
        return interfaceId == 0x4e2312e0; // ERC1155Receiver
    }
}
